+/**
+ * Sanitize hot spot attributes to prevent XSS attacks
+ * Filters out dangerous attributes like event handlers
+ * @param {Object} attributes - Raw attributes from config
+ * @returns {Object} Sanitized attributes
+ */
+function sanitizeHotSpotAttributes(attributes) {
+    const sanitized = {};
+    const eventHandlerPattern = /^on[a-z]+$/i;
+    const allowedAttributes = ['href', 'title', 'target', 'rel', 'class', 'id', 'data-*'];
+    
+    for (const key in attributes) {
+        if (eventHandlerPattern.test(key)) {
+            // Skip event handler attributes (onclick, onmouseover, etc.)
+            continue;
+        }
+        if (allowedAttributes.includes(key) || key.startsWith('data-')) {
+            sanitized[key] = attributes[key];
+        }
+    }
+    
+    return sanitized;
+}
+
