+/**
+ * Sanitizes SVG strings to prevent DOM-based XSS vulnerabilities.
+ * Removes dangerous attributes and patterns that could execute scripts.
+ * 
+ * @param {string} svgString - The SVG string to sanitize
+ * @returns {string} - The sanitized SVG string
+ */
+function sanitizeSvgString(svgString) {
+  if (typeof svgString !== 'string') {
+    return svgString;
+  }
+  
+  // Remove event handler attributes (on* attributes)
+  // This prevents execution of JavaScript via event handlers
+  let sanitized = svgString.replace(/on\w+\s*=\s*["'][^"']*["']/gi, '');
+  
+  // Remove javascript: URLs in href, src, and other attributes
+  sanitized = sanitized.replace(/(href|src|action|formaction|data)\s*=\s*["']?javascript:/gi, '');
+  
+  // Remove vbscript: URLs
+  sanitized = sanitized.replace(/(href|src|action|formaction|data)\s*=\s*["']?vbscript:/gi, '');
+  
+  // Remove data: URLs that could contain scripts
+  sanitized = sanitized.replace(/(href|src|action|formaction|data)\s*=\s*["']?data:[^"']*script/gi, '');
+  
+  return sanitized;
+}
+
 /**
  * Fix up an SVG string to make it compatible with the renderer.
  * @param {string} svgString - The SVG string to fix up
  * @returns {string} - The fixed up SVG string
