+/**
+ * Check if a string is a filesystem URI
+ * @param uri - The URI to check
+ * @returns true if it's a filesystem URI
+ */
+export function isFileSystemUri(uri: string): boolean {
+	return uri.startsWith('filesystem://') || uri.startsWith('filesystem-v2://');
+}
+
+export function isFileSystemUriEmpty(uri: string): boolean {
+	return isFileSystemUri(uri) && !uri.replace(/^filesystem:\/\/|^filesystem-v2:\/\//, '').trim();
+}
